// Parser robusto da saída do Agente Gemini

// 1. Pega a saída bruta da IA
let raw = items[0].json.output || '';

// 2. Remove markdown code fences
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '');
raw = raw.replace(/\s*```$/, '').trim();

// 3. Extrai o primeiro bloco JSON { ... } da string
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  raw = jsonMatch[0];
}

// 4. Parse do JSON
let aiOutput;
try {
  aiOutput = JSON.parse(raw);
} catch (error) {
  aiOutput = { "intenção": "pergunta_frequente", mensagem: raw };
}

// 5. Normaliza intenção
const intencao = aiOutput["intenção"] || aiOutput["intencao"] || "pergunta_frequente";
aiOutput["intenção"] = intencao;

// 6. Para informar_imoveis: garante array
if (aiOutput["intenção"] === "informar_imoveis") {
  if (typeof aiOutput.mensagem === "string") {
    try {
      const parsed = JSON.parse(aiOutput.mensagem);
      if (Array.isArray(parsed)) {
        aiOutput.mensagem = parsed;
      } else {
        aiOutput["intenção"] = "pergunta_frequente";
      }
    } catch (e) {
      aiOutput["intenção"] = "pergunta_frequente";
    }
  }
  if (!Array.isArray(aiOutput.mensagem)) {
    aiOutput["intenção"] = "pergunta_frequente";
  }
}

// Helper: converte dd/MM/yyyy para yyyy-MM-dd
function formatarData(dataStr) {
  if (!dataStr) return null;
  const partes = dataStr.split("/");
  if (partes.length === 3) return partes[2] + "-" + partes[1] + "-" + partes[0];
  return dataStr; // já pode estar em formato ISO
}

// Helper: garante formato HH:mm:ss
function formatarHora(horaStr) {
  if (!horaStr) return null;
  return horaStr.length === 5 ? horaStr + ":00" : horaStr;
}

// 7. Formata dados de agendamento
let dataFormatada = null;
let horaAgendamento = null;
let dataAntiga = null;
let horaAntiga = null;
let codigoImovel = null;
let corretor = "Carlos Mendes";

if (aiOutput["intenção"] === "agendamento_confirmado" || aiOutput["intenção"] === "reagendamento_solicitado") {
  dataFormatada = formatarData(aiOutput.data_agendamento);
  horaAgendamento = formatarHora(aiOutput.hora_agendamento);
  codigoImovel = aiOutput.codigo_imovel || null;
  corretor = aiOutput.corretor || "Carlos Mendes";

  if (aiOutput["intenção"] === "reagendamento_solicitado") {
    dataAntiga = formatarData(aiOutput.data_antiga);
    horaAntiga = formatarHora(aiOutput.hora_antiga);
  }
}

// 8. Retorna objeto padronizado
return {
  "intenção": aiOutput["intenção"],
  mensagem: aiOutput.mensagem,
  data_agendamento: dataFormatada,
  hora_agendamento: horaAgendamento,
  data_antiga: dataAntiga,
  hora_antiga: horaAntiga,
  codigo_imovel: codigoImovel,
  corretor: corretor
};

// Lê a mensagem da IA via referência explícita ao Code1
// Independente de qual nó passou o dado antes
const mensagem = $('Code1').first().json.mensagem;
let imoveis;

if (Array.isArray(mensagem)) {
  imoveis = mensagem;
} else if (typeof mensagem === "string") {
  try {
    const parsed = JSON.parse(mensagem);
    imoveis = Array.isArray(parsed) ? parsed : [{ imagem_url: "", texto: mensagem }];
  } catch (e) {
    imoveis = [{ imagem_url: "", texto: mensagem }];
  }
} else {
  imoveis = [];
}

// Garantir pelo menos 1 item
if (imoveis.length === 0) {
  imoveis = [{ imagem_url: "", texto: "" }];
}

return imoveis.map(function(imovel) { return { json: imovel }; });

// Pega os dados do cliente de forma segura
const dadosIniciais = $('Dados2').first().json;

// Mensagem call-to-action após os cards
const titulo = "*Aqui estão os imóveis que selecionei para você!* 🏡";
const corpo1 = "A jornada para um novo lar pode parecer complexa, mas meu trabalho é torná-la simples e segura para você. O primeiro passo é visitar e ver qual deles faz seu coração bater mais forte.";
const corpo2 = "Me informe a referência do imóvel que despertou seu interesse e eu cuido de todo o agendamento da visita. Simples assim.";
const fechamento = "*Qual deles vamos conhecer primeiro?*";

const mensagemFormatada = `${titulo}\n\n${corpo1}\n\n${corpo2}\n\n${fechamento}`;

return [{
  json: {
    mensagem_final: mensagemFormatada,
    instance: dadosIniciais.instance,
    remoteJid: dadosIniciais.remoteJid
  }
}];
